#define fp float

#define NUMBER_PAR_PER_BOX 100

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
	fp x, y, z;
} THREE_VECTOR;

typedef struct {
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str {
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str {
	fp alpha;
} par_str;

typedef struct dim_str {
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void
kernel_gpu_opencl(	par_str par,
					dim_str dim,
					__global box_str* box,
					__global FOUR_VECTOR* rv,
					__global fp* qv,
					__global FOUR_VECTOR* fv)
{
	const long l = (long)get_group_id(0);
	const int tx = (int)get_local_id(0);
	const int lsize = (int)get_local_size(0);

	if (l >= dim.number_boxes) return;

	const fp alpha = par.alpha;
	const fp a2 = (fp)2.0f * alpha * alpha;

	const long first_i = box[l].offset;

	for (int i = tx; i < NUMBER_PAR_PER_BOX; i += lsize) {
		const FOUR_VECTOR rAi = rv[first_i + i];
		FOUR_VECTOR fAi = fv[first_i + i];

		for (int k = 0; k < (1 + box[l].nn); k++) {
			int pointer;
			if (k == 0) {
				pointer = (int)l;
			} else {
				pointer = box[l].nei[k - 1].number;
			}

			const long first_j = box[pointer].offset;

			for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
				const FOUR_VECTOR rBj = rv[first_j + j];
				const fp qBj = qv[first_j + j];

				const fp r2 = rAi.v + rBj.v - DOT(rAi, rBj);
				const fp u2 = a2 * r2;
				const fp vij = exp(-u2);
				const fp fs = (fp)2.0f * vij;

				const fp dx = rAi.x - rBj.x;
				const fp dy = rAi.y - rBj.y;
				const fp dz = rAi.z - rBj.z;

				const fp fxij = fs * dx;
				const fp fyij = fs * dy;
				const fp fzij = fs * dz;

				fAi.v += qBj * vij;
				fAi.x += qBj * fxij;
				fAi.y += qBj * fyij;
				fAi.z += qBj * fzij;
			}
		}

		fv[first_i + i] = fAi;
	}
}
